import { defineStore } from 'pinia'

export const useTaskStore = defineStore('taskStore', {
  state: () => ({
    tasks: [] as { id: number; text: string; completed: boolean }[],
  }),
  actions: {
    addTask(text: string) {
      if (text.trim()) {
        this.tasks.push({ id: Date.now(), text, completed: false })
      }
    },
    toggleTask(id: number) {
      const task = this.tasks.find(t => t.id === id)
      if (task) task.completed = !task.completed
    },
    removeTask(id: number) {
      this.tasks = this.tasks.filter(t => t.id !== id)
    },
  },
})
<script setup lang="ts">
import { useTaskStore } from '../stores/taskStore'

const taskStore = useTaskStore()
</script>

<template>
    <ul class="task-list">
      <li v-for="task in taskStore.tasks" :key="task.id" class="task-item">
        <span :class="{ completed: task.completed }">{{ task.text }}</span>
        <div class="task-actions">
          <!-- Botón de completar tarea -->
          <button @click="taskStore.toggleTask(task.id)" :aria-label="task.completed ? 'Marcar como pendiente' : 'Marcar como completada'">
            <FontAwesomeIcon :icon="['fas', 'check']" />
            <span class="sr-only">{{ task.completed ? 'Marcar como pendiente' : 'Marcar como completada' }}</span>
          </button>
          
          <!-- Botón de eliminar tarea -->
          <button @click="taskStore.removeTask(task.id)" aria-label="Eliminar tarea">
            <FontAwesomeIcon :icon="['fas', 'trash']" />
            <span class="sr-only">Eliminar tarea</span>
          </button>
        </div>
      </li>
    </ul>
  </template>
<script setup lang="ts">
import { ref } from 'vue'
import { useTaskStore } from '../stores/taskStore'

const taskStore = useTaskStore()
const newTask = ref('')

const addTask = () => {
  taskStore.addTask(newTask.value)
  newTask.value = ''
}
</script>

<template>
    <div class="container">
      <h1>Lista de Tareas</h1>
      <div class="task-input">
        <input v-model="newTask" placeholder="Nueva tarea" />
        <button @click="addTask" aria-label="Agregar tarea">
          <FontAwesomeIcon :icon="['fas', 'plus']" />
          <span class="sr-only">Agregar tarea</span>
        </button>
      </div>
      <TaskList />
    </div>
  </template>
